      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { title } = req.body;
  if (!title) {
    return sendError(res, 400, 'INVALID_INPUT', 'Title is required');
  }
  try {
    const task = await tasksService.createTask(req.params.projectId, title);
    res.status(201).json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to create task');
  }
});

router.get('/', async (req, res) => {
  try {
    const tasks = await tasksService.getTasksByProjectId(req.params.projectId);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to get tasks');
  }
});

router.patch('/:taskId', async (req, res) => {
  const { status } = req.body;
  if (!status || !['completed', 'in_progress'].includes(status)) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid status');
  }
  try {
    const task = await tasksService.updateTaskStatus(req.params.taskId, status);
    if (!task) {
      return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
    }
    res.json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to update task status');
  }
});

module.exports = router;
