      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('../../lib/id');

let tasksStore = [];

const createTask = async (projectId, title) => {
  const taskId = randomUUID();
  const task = { id: taskId, projectId, title, status: 'in_progress' };
  tasksStore.push(task);
  return task;
};

const getTasksByProjectId = async (projectId) => {
  return tasksStore.filter(task => task.projectId === projectId);
};

const updateTaskStatus = async (taskId, status) => {
  const task = tasksStore.find(task => task.id === taskId);
  if (task) {
    task.status = status;
  }
  return task;
};

module.exports = { createTask, getTasksByProjectId, updateTaskStatus };
